INSERT INTO `attraction` (name, city, category, description, address, ticket_price, opening_hours, image_url, rating, review_count, latitude, longitude) VALUES
('西湖', '杭州', '自然风光', '西湖位于浙江省杭州市西部，是中国大陆首批国家重点风景名胜区和中国十大风景名胜之一。它是中国大陆主要的观赏性淡水湖泊之一，也是现今《世界遗产名录》中少数几个和中国唯一一个湖泊类文化遗产。', '浙江省杭州市西湖区龙井路1号', 0.00, '全天开放', 'https://images.unsplash.com/photo-1599571234909-29ed5d1321d6?w=800', 4.8, 1280, 30.2370, 120.1400),
('故宫博物院', '北京', '历史古迹', '北京故宫是中国明清两代的皇家宫殿，旧称为紫禁城，位于北京中轴线的中心，是中国古代宫廷建筑之精华。北京故宫以三大殿为中心，占地面积72万平方米，建筑面积约15万平方米，有大小宫殿七十多座，房屋九千余间。', '北京市东城区景山前街4号', 60.00, '08:30-17:00(旺季)/08:30-16:30(淡季)', 'https://images.unsplash.com/photo-1547981609-4b6bfe67ca0b?w=800', 4.9, 3500, 39.9160, 116.3970),
('外滩', '上海', '历史古迹', '外滩位于上海市黄浦区的黄浦江畔，即外黄浦滩，为中国历史文化街区。1844年起这一带被划为英国租界，成为上海十里洋场的真实写照，也是旧上海租界区以及整个上海近代城市开始的起点。', '上海市黄浦区中山东一路', 0.00, '全天开放', 'https://images.unsplash.com/photo-1545893835-abaa50cbe628?w=800', 4.7, 2100, 31.2400, 121.4900),
('成都大熊猫繁育研究基地', '成都', '主题公园', '成都大熊猫繁育研究基地，是中国政府实施大熊猫等濒危野生动物迁地保护工程的主要研究基地之一，国家AAAA级旅游景区。是我国乃至全球知名的集大熊猫科研繁育、保护教育、教育旅游、熊猫文化建设为一体的大熊猫等珍稀濒危野生动物保护研究机构。', '四川省成都市成华区熊猫大道1375号', 55.00, '07:30-18:00', 'https://images.unsplash.com/photo-1564349683136-77e08dba1ef7?w=800', 4.7, 1800, 30.7320, 104.1400),
('丽江古城', '丽江', '古镇', '丽江古城位于云南省丽江市古城区，又名大研镇，坐落在丽江坝中部，始建于宋末元初，地处云贵高原，面积为7.279平方公里。丽江古城内的街道依山傍水修建，以红色角砾岩铺就，有四方街、木府、五凤楼、黑龙潭等景点。', '云南省丽江市古城区', 50.00, '全天开放', 'https://images.unsplash.com/photo-1528164344705-47542687000d?w=800', 4.6, 1500, 26.8720, 100.2300),
('三亚亚龙湾', '三亚', '海滩', '亚龙湾是海南省三亚市东郊的一处优质热带海滨风景区，沙滩平缓开阔，沙粒洁白细软，海水清澈澄莹，海底资源丰富，生长众多原始热带植被，颇具热带海岛风情。被誉为"天下第一湾"。', '海南省三亚市亚龙湾国家旅游度假区', 0.00, '全天开放', 'https://images.unsplash.com/photo-1540202404-a2f29016b523?w=800', 4.7, 950, 18.2200, 109.6200),
('黄山风景区', '黄山', '山脉', '黄山，中华十大名山之一，天下第一奇山。位于安徽省黄山市境内，有72峰，主峰莲花峰海拔1864米，与光明顶、天都峰并称三大黄山主峰。黄山是安徽旅游的标志，是中国十大风景名胜唯一的山岳风光。', '安徽省黄山市黄山区', 190.00, '06:00-17:00', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=800', 4.8, 2200, 30.1300, 118.1600),
('兵马俑', '西安', '博物馆', '兵马俑，即秦始皇陵兵马俑，亦简称秦兵马俑或秦俑，位于今陕西省西安市临潼区秦始皇陵以东1.5千米处的兵马俑坑内。兵马俑是古代墓葬雕塑的一个类别，即制成兵马形状的殉葬品。', '陕西省西安市临潼区秦陵北路', 120.00, '08:30-18:00', 'https://images.unsplash.com/photo-1565967511849-76a60a516170?w=800', 4.8, 3100, 34.3850, 109.2730),
('鼓浪屿', '厦门', '自然风光', '鼓浪屿，原名圆沙洲，位于福建省厦门市思明区鼓浪屿街道。因岛西南方海滩上有一块两米多高、中有洞穴的礁石，每当涨潮水涌，浪击礁石，声似擂鼓，人们称鼓浪石，鼓浪屿因此而得名。', '福建省厦门市思明区鼓浪屿', 35.00, '全天开放', 'https://images.unsplash.com/photo-1559064275-b6541c15dd1b?w=800', 4.6, 1100, 24.4480, 118.0670),
('张家界国家森林公园', '张家界', '山脉', '张家界国家森林公园位于湖南省张家界市境内，是中国第一个国家森林公园。1992年，由张家界国家森林公园等三大景区构成的武陵源风景名胜区被联合国教科文组织列入《世界自然遗产名录》。', '湖南省张家界市武陵源区', 228.00, '07:00-18:00', 'https://images.unsplash.com/photo-1529921879218-f99528d25cda?w=800', 4.7, 1600, 29.3400, 110.4700),
('布达拉宫', '拉萨', '历史古迹', '布达拉宫坐落于西藏自治区首府拉萨市区西北玛布日山上，是世界上海拔最高，集宫殿、城堡和寺院于一体的宏伟建筑，也是西藏最庞大、最完整的古代宫堡建筑群。', '西藏自治区拉萨市城关区北京中路35号', 200.00, '09:00-16:00', 'https://images.unsplash.com/photo-1531842477198-4281b3da2a6b?w=800', 4.8, 2800, 29.6570, 91.1170),
('桂林漓江', '桂林', '自然风光', '漓江，属珠江流域西江水系，为支流桂江上游河段的通称，位于广西壮族自治区东北部。漓江段全长164公里，沿江河床多为水质卵石，泥沙量小，水质清澈，两岸多为岩溶地貌。旅游资源丰富，著名的桂林山水就在漓江上。', '广西壮族自治区桂林市', 215.00, '08:00-18:00', 'https://images.unsplash.com/photo-1530076886461-ce58ea8abe24?w=800', 4.7, 1900, 25.2700, 110.2800);
INSERT INTO `hotel` (name, city, address, star_level, price_range, price_min, price_max, description, phone, rating, review_count) VALUES
('北京王府井希尔顿酒店', '北京', '东城区王府井大街8号', 5, '800-2000', 800.00, 2000.00, '坐落于北京繁华的王府井商圈，毗邻故宫和天安门广场，交通便利，设施豪华。', '010-58128888', 4.7, 520),
('杭州西湖国宾馆', '杭州', '西湖区杨公堤18号', 5, '1000-3000', 1000.00, 3000.00, '位于西湖核心景区，拥有私家湖岸线，园林式建筑风格，被誉为"西湖第一名园"。', '0571-87979889', 4.9, 680),
('上海外滩华尔道夫酒店', '上海', '黄浦区中山东一路2号', 5, '1500-5000', 1500.00, 5000.00, '坐落于外滩核心位置，历史建筑与现代奢华完美融合，坐拥浦江两岸壮丽景色。', '021-63229988', 4.8, 420),
('三亚海棠湾红树林度假酒店', '三亚', '海棠区海棠北路58号', 5, '600-2500', 600.00, 2500.00, '位于海棠湾C位，拥有私家沙滩和多个泳池，是家庭度假的理想之选。', '0898-88958888', 4.6, 380),
('成都博舍酒店', '成都', '锦江区笔帖式街81号', 5, '1200-3500', 1200.00, 3500.00, '坐落于成都远洋太古里，融合传统四合院与现代设计，是成都最具特色的精品酒店之一。', '028-66369999', 4.8, 310),
('西安索菲特传奇酒店', '西安', '碑林区东新街319号', 5, '900-2500', 900.00, 2500.00, '原人民大厦改造而成，法式优雅与中式传统完美结合，毗邻钟楼和回民街。', '029-87928888', 4.7, 290),
('丽江悦榕庄', '丽江', '古城区束河古镇', 5, '1200-4000', 1200.00, 4000.00, '位于束河古镇，每栋别墅均能远眺玉龙雪山，纳西族建筑风格，宁静致远。', '0888-5331111', 4.8, 350),
('厦门康莱德酒店', '厦门', '思明区演武西路186号', 5, '800-2500', 800.00, 2500.00, '世茂海峡大厦双子塔内，高空酒店俯瞰鼓浪屿和厦门大学，景观绝佳。', '0592-2558888', 4.7, 260),
('北京如家快捷酒店(前门店)', '北京', '西城区前门大街88号', 2, '200-400', 200.00, 400.00, '经济型连锁酒店，位于前门大街，出行便利，性价比高。', '010-63018888', 4.0, 850),
('杭州青旅国际青年旅舍', '杭州', '上城区河坊街58号', 2, '50-150', 50.00, 150.00, '位于河坊街历史文化街区，交通便利，氛围轻松，深受背包客喜爱。', '0571-87808888', 4.2, 1200);
INSERT INTO `restaurant` (name, city, address, cuisine_type, price_range, price_per_person, description, phone, rating, review_count) VALUES
('全聚德烤鸭店(前门店)', '北京', '东城区前门大街32号', '本地特色', '100-200', 150.00, '创建于1864年的百年老字号，以挂炉烤鸭闻名于世，是北京饮食文化的代表。', '010-65112418', 4.5, 3200),
('楼外楼', '杭州', '西湖区孤山路30号', '本地特色', '100-300', 180.00, '创建于1848年，坐拥西湖美景，以西湖醋鱼、东坡肉等杭帮菜名扬天下。', '0571-87969023', 4.6, 2800),
('老正兴菜馆', '上海', '黄浦区福州路556号', '本地特色', '80-200', 120.00, '创建于1862年的上海本帮菜老店，油爆虾、八宝鸭等是招牌菜。', '021-63222624', 4.4, 1900),
('皇城老妈火锅', '成都', '武侯区二环路南三段20号', '火锅', '80-150', 100.00, '成都火锅的代表品牌，麻辣鲜香，环境优雅，是体验川味火锅的绝佳去处。', '028-85139999', 4.7, 3500),
('滇味园', '丽江', '古城区五一街文治巷76号', '本地特色', '50-100', 70.00, '主打云南特色菜，过桥米线、汽锅鸡、野生菌火锅是必点菜品。', '0888-5121888', 4.3, 680),
('海味轩海鲜餐厅', '三亚', '天涯区三亚湾路188号', '海鲜', '150-500', 250.00, '位于三亚湾海边，每天从渔港直送新鲜海鲜，清蒸石斑鱼、椒盐皮皮虾最受欢迎。', '0898-88668888', 4.5, 1500),
('回民街贾三灌汤包子', '西安', '碑林区回民街北院门93号', '小吃', '30-60', 45.00, '西安回民街的传奇小吃店，灌汤包皮薄馅大汁多，是来西安必吃的美食。', '029-87258888', 4.6, 4200),
('临江楼土菜馆', '黄山', '黄山区汤口镇寨西', '本地特色', '50-120', 80.00, '黄山脚下的农家菜馆，臭鳜鱼、毛豆腐等徽菜经典，食材新鲜地道。', '0559-5562888', 4.3, 560),
('无味舒食(鼓浪屿店)', '厦门', '思明区鼓浪屿龙头路168号', '素食', '60-120', 80.00, '岛上文艺的素食餐厅，环境清幽，菜品精致有创意。', '0592-2089888', 4.4, 420),
('胡师傅三下锅', '张家界', '永定区南庄坪', '本地特色', '50-100', 70.00, '张家界特色土家菜，三下锅是招牌，腊肉、豆腐、肥肠三种主料炖煮，味道浓郁。', '0744-8886888', 4.2, 380);
